            member _.ListPets (limit : int option, ct : System.Threading.CancellationToken option) =
                async {
                    let! ct = Async.CancellationToken

                    let uri =
                        System.Uri (
                            (match client.BaseAddress with
                             | null -> System.Uri "https://api.example.test/v1/public/"
                             | v -> v),
                            System.Uri (
                                ("pets"
                                 + (if "pets".IndexOf (char 63) >= 0 then "&" else "?")
                                 + "limit="
                                 + ((limit.ToString ()) |> System.Uri.EscapeDataString)),
                                System.UriKind.Relative
                            )
                        )

                    use httpMessage =
                        new System.Net.Http.HttpRequestMessage (
                            Method = System.Net.Http.HttpMethod.Get,
                            RequestUri = uri
                        )

                    do httpMessage.Headers.Add ("Accept", "application/json")
                    let! response = client.SendAsync (httpMessage, ct) |> Async.AwaitTask
                    let response = response.EnsureSuccessStatusCode ()
                    use response = response
                    let! responseStream = response.Content.ReadAsStreamAsync ct |> Async.AwaitTask

                    let! jsonNode =
                        System.Text.Json.Nodes.JsonNode.ParseAsync (responseStream, cancellationToken = ct)
                        |> Async.AwaitTask

                    let jsonNode =
                        (match jsonNode with
                         | null ->
                             raise (
                                 System.ArgumentNullException
                                     "Response from server was the JSON null object; expected a non-nullable type Pet list"
                             )
                         | jsonNode -> jsonNode)

                    return
                        jsonNode.AsArray ()
                        |> Seq.map (fun elt ->
                            (match elt with
                             | null ->
                                 raise (
                                     System.ArgumentNullException
                                         "Expected element of array (element type Pet) to be non-null, but found a null element"
                                 )
                             | elt -> Pet.jsonParse elt)
                        )
                        |> List.ofSeq
                }
                |> (fun a -> Async.StartAsTask (a, ?cancellationToken = ct))
